-	try {
-		ensureSettingsDir();
-		const content = JSON.stringify(settings, null, 2);
-		storage.writeFile(SETTINGS_PATH, content);
-		cachedSettings = settings;
-		return true;
-	} catch (error) {
-		console.error(`Failed to save settings to ${SETTINGS_PATH}:`, error);
-		return false;
-	}
-}
